#include <stdio.h>

long long binpow(long long x, long long k, long long mod) {
    long long res = 1;
    while (k > 0) {
        if (k & 1) {
            res = (res * x) % mod;
        }
        x = (x * x) % mod;
        k >>= 1;
    }
    return res;
}

